1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const BLOCK_OF_3_BASE_PREMIUM = 60;
7	const LOYALTY_THRESHOLD_YEARS = 2;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	
13	const BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const INSURANCE_VALUE: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
34	type QuoteStep = { op: "quote"; items: Item[] };
35	type Damage = { itemType: string; amount: number };
36	type Incident = { cause: string; damages: Damage[] };
37	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
38	type Step = QuoteStep | ClaimStep;
39	type Customer = { yearsWithMHPCO: number };
40	type Scenario = { customer: Customer; steps: Step[] };
41	type QuoteResult = { premium: number };
42	type ClaimResult = { payout: number; remainingCap: number };
43	type StepResult = QuoteResult | ClaimResult;
44	
45	type Policy = { items: Item[]; insuranceSum: number; cap: number; capRemaining: number };
46	
47	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
48	
49	const itemSurcharges = (item: Item): number => {
50	  const base = BASE_PREMIUM[item.type];
51	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
52	  const highEnchSurcharge =
53	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
54	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
55	      : 0;
56	  return curseSurcharge + highEnchSurcharge;
57	};
58	
59	const countByType = (items: Item[]): Map<string, number> => {
60	  const counts = new Map<string, number>();
61	  for (const item of items) {
62	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
63	  }
64	  return counts;
65	};
66	
67	const componentGroupBase = (type: string, count: number): number =>
68	  count === 3 ? BLOCK_OF_3_BASE_PREMIUM : count * BASE_PREMIUM[type];
69	
70	const policyBase = (items: Item[]): number => {
71	  const components = items.filter(isComponent);
72	  const mainItems = items.filter((item) => !isComponent(item));
73	  const mainBase = mainItems.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
74	  const componentBase = Array.from(countByType(components)).reduce(
75	    (sum, [type, count]) => sum + componentGroupBase(type, count),
76	    0,
77	  );
78	  return mainBase + componentBase;
79	};
80	
81	const sumItemSurcharges = (items: Item[]): number =>
82	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
83	
84	const loyaltyDiscount = (customer: Customer, base: number): number =>
85	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
86	
87	const followUpDiscount = (isFollowUp: boolean, base: number): number =>
88	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
89	
90	const quoteStep = (step: QuoteStep, customer: Customer, isFollowUp: boolean): QuoteResult => {
91	  const base = policyBase(step.items);
92	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
93	  const premium =
94	    base +
95	    firstInsurance -
96	    loyaltyDiscount(customer, base) -
97	    followUpDiscount(isFollowUp, base) +
98	    sumItemSurcharges(step.items) +
99	    PROCESSING_FEE;
100	  return { premium: Math.ceil(premium) };
101	};
102	
103	const insuranceSum = (items: Item[]): number =>
104	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
105	
106	const makePolicy = (items: Item[]): Policy => {
107	  const sum = insuranceSum(items);
108	  const cap = sum * CAP_MULTIPLIER;
109	  return { items, insuranceSum: sum, cap, capRemaining: cap };
110	};
111	
112	const damagePayout = (damage: Damage): number => damage.amount - DEDUCTIBLE;
113	
114	const claimStep = (step: ClaimStep, policies: Policy[]): ClaimResult => {
115	  const policy = policies[step.policy];
116	  const payout = step.incident.damages.reduce((sum, d) => sum + damagePayout(d), 0);
117	  policy.capRemaining -= payout;
118	  return { payout, remainingCap: policy.capRemaining };
119	};
120	
121	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
122	  const policies: Policy[] = [];
123	  let quoteCount = 0;
124	  const results: StepResult[] = scenario.steps.map((step) => {
125	    if (step.op === "quote") {
126	      const isFollowUp = quoteCount > 0;
127	      quoteCount += 1;
128	      policies.push(makePolicy(step.items));
129	      return quoteStep(step, scenario.customer, isFollowUp);
130	    }
131	    return claimStep(step, policies);
132	  });
133	  return { results };
134	};
